class Command(BaseCommand):
    help = 'Seed all university courses from LMS scrape'

    def add_arguments(self, parser):
        parser.add_argument('--clear', action='store_true',
                            help='Delete all existing courses, colleges, and departments first')

    def handle(self, *args, **options):
        if options['clear']:
            Course.objects.all().delete()
            Department.objects.all().delete()
            College.objects.all().delete()
            self.stdout.write(self.style.WARNING('Cleared existing data.'))

        college_cache = {}
        dept_cache    = {}
        created_c = skipped_c = 0

        for title, college_name, dept_name, year, code in COURSES:
            # College
            if college_name not in college_cache:
                col, _ = College.objects.get_or_create(
                    college_name=college_name,
                    defaults={'name': college_name}
                )
                college_cache[college_name] = col
            college = college_cache[college_name]

            # Department
            dept_key = (dept_name, college.pk)
            if dept_key not in dept_cache:
                dept, _ = Department.objects.get_or_create(
                    name=dept_name, college=college
                )
                dept_cache[dept_key] = dept
            dept = dept_cache[dept_key]

            # Course — skip if code already exists
            if Course.objects.filter(course_code=code).exists():
                skipped_c += 1
                continue

            Course.objects.create(
                course_code=code,
                title=title,
                credits=3,
                total_hours=3,
                college=college,
                department=dept,
                year_level=year,
            )
            created_c += 1

        total = len(COURSES)
        self.stdout.write(self.style.SUCCESS(
            f'Done. {created_c} courses created, {skipped_c} skipped (already exist). '
            f'Total in dataset: {total}.'
        ))
        self.stdout.write(f'Colleges: {College.objects.count()} | '
                          f'Departments: {Department.objects.count()} | '
                          f'Courses: {Course.objects.count()}')
